import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    best_node = None
    minimum_penalty_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        arrival_time = current_time + travel_time(cur_truck_pos, customer_pos)
        window_start, window_end = time_windows[i]

        # Calculate penalty based on time window
        if arrival_time < window_start:
            penalty_time = window_start + travel_time(customer_pos, depot_pos)  # Consider wait until window opens then return to depot
        elif arrival_time > window_end:
            penalty_time = arrival_time + travel_time(customer_pos, depot_pos)  # Consider direct penalty for being late
        else:
            penalty_time = arrival_time + travel_time(customer_pos, depot_pos)  # No penalty, just end time

        # Update best node selection based on minimum end time or penalty time
        if penalty_time < minimum_penalty_time:
            minimum_penalty_time = penalty_time
            best_node = i

    return best_node
